begin;create extension if not exists pgtap with schema extensions;set local search_path=public,extensions;select plan(90);
insert into auth.users(instance_id,id,aud,role,email,encrypted_password,email_confirmed_at,raw_app_meta_data,raw_user_meta_data,created_at,updated_at,confirmation_token,email_change,email_change_token_new,recovery_token) values('00000000-0000-0000-0000-000000000000','82000000-0000-4000-8000-000000000001','authenticated','authenticated','checkin-owner@example.test','',now(),'{}','{"display_name":"Check-in Owner"}',now(),now(),'','','','');
set local role authenticated;select set_config('request.jwt.claims','{"sub":"82000000-0000-4000-8000-000000000001","role":"authenticated","email":"checkin-owner@example.test","aal":"aal2"}',true);
select lives_ok($$select * from app.create_business_with_owner('Check-in Test','checkin-test','Main','main','America/Chicago')$$,'tenant created');
select lives_ok($$select app.create_customer_household_with_pet((select id from businesses where public_slug='checkin-test'),'Pat','Owner','','checkin@example.test',null,'Milo','Mixed breed','2020-01-01',false,'male')$$,'customer and pet created');
select lives_ok($$select app.create_service_draft((select id from businesses where public_slug='checkin-test'),'boarding','Boarding','Boarding','overnight_date_range',null,'staff_approval','Stay')$$,'service created');
select lives_ok($$select app.publish_service_version((select business_id from services),(select id from services),(select id from service_versions),(select id from locations),false,true,true,false)$$,'service published');
select lives_ok($$select app.configure_capacity_pool((select business_id from services),(select id from locations),(select id from services),'Capacity','count',2,2)$$,'capacity configured');
insert into capacity_resources(business_id,capacity_pool_id,resource_code,label,resource_type,max_pets) values((select business_id from capacity_pools),(select id from capacity_pools),'K-01','Kennel 01','kennel',1);
select lives_ok($$select * from app.create_pricing_bundle((select id from businesses where public_slug='checkin-test'),(select id from locations),'USD','USD','Deposit','percentage',5000,0,24,5000,10000,'Agreement','Accepted payment terms.','Half deposit.')$$,'pricing configured');
select lives_ok($$select app.add_price_rate((select business_id from price_books),(select id from price_book_versions),(select id from locations),(select id from service_versions),'night',10000,'Night',100,null,null)$$,'rate created');
select lives_ok($$select app.publish_pricing_bundle((select business_id from price_books),(select id from price_book_versions),(select id from commercial_policy_versions),current_date)$$,'pricing published');
select lives_ok($$select app.create_booking_request((select business_id from services),(select id from locations),(select id from customers),(select id from pets),(select id from services),now()+interval '2 days',now()+interval '4 days',1,2,null,'staff','checkin-booking')$$,'booking requested');
select lives_ok($$select app.resolve_booking_review((select business_id from bookings),(select id from bookings),'approved','Manager approved check-in test','checkin-approval')$$,'booking approved');
select lives_ok($$select app.issue_booking_invoice((select business_id from bookings),(select id from bookings),'checkin-invoice')$$,'invoice issued');
select lives_ok($$select app.record_manual_payment((select business_id from invoices),(select id from invoices),(select location_id from invoices),10000,'check','CHECK-IN','checkin-deposit')$$,'deposit posted');
select is((select status from bookings),'confirmed','deposit confirms booking');
select lives_ok($$select app.record_booking_arrival((select business_id from bookings),(select id from bookings),'arrival-once')$$,'arrival recorded');
select is(app.record_booking_arrival((select business_id from bookings),(select id from bookings),'arrival-retry'),(select id from operational_visits),'arrival retry returns same visit');
select is((select count(*) from operational_visits),1::bigint,'one operational visit created');
select is((select status from operational_visits),'arrived','arrival remains distinct from check-in');
select is((select status from pet_visits),'arrived','pet is physically arrived');
insert into booking_action_items(business_id,booking_id,booking_revision_id,action_type,audience,title,metadata) values((select business_id from bookings),(select id from bookings),(select id from booking_revisions order by revision_number desc limit 1),'intake','manager','Review changed arrival instruction','{"overrideable":true}');
select throws_ok($$select app.complete_pet_check_in((select business_id from bookings),(select id from bookings),(select id from pets),'Pat Owner','owner','photo_id','["name:Milo","breed:Mixed breed"]','{}','[]','blocked-checkin')$$,'P0001','blocking booking actions remain open','open action blocks custody acceptance');
select lives_ok($$select app.resolve_check_in_blocker((select business_id from bookings),(select id from booking_action_items),'approved_exception','Manager verified a safe visit-only exception','{"review":"completed"}','resolve-intake')$$,'manager resolves policy-marked blocker');
select is((select status from booking_action_items where title='Review changed arrival instruction'),'resolved','resolved blocker closes explicitly');
select is(app.resolve_check_in_blocker((select business_id from bookings),(select id from booking_action_items),'approved_exception','Manager verified a safe visit-only exception','{}','resolve-intake'),(select id from check_in_blocker_resolutions),'resolution retry is idempotent');
select is((select count(*) from check_in_blocker_resolutions),1::bigint,'one blocker resolution retained');
select throws_ok($$update check_in_blocker_resolutions set reason='rewritten evidence'$$,'P0001','commercial snapshots are immutable','manager resolution cannot be rewritten');
select lives_ok($$select app.complete_pet_check_in((select business_id from bookings),(select id from bookings),(select id from pets),'Pat Owner','owner','photo_id','["name:Milo","breed:Mixed breed"]','{"notes":"No visible concerns"}','[{"category":"belonging","name":"Blue leash","quantity":1,"unit":"item","storage":"Cubby A","return_expected":true}]','checkin-once')$$,'custody accepted');
select is(app.complete_pet_check_in((select business_id from bookings),(select id from bookings),(select id from pets),'Pat Owner','owner','photo_id','["name:Milo","breed:Mixed breed"]','{"notes":"No visible concerns"}','[]','checkin-once'),(select id from check_in_records),'check-in retry returns same record');
select is((select status from operational_visits),'in_care','visit enters care after all pets check in');
select is((select status from pet_visits),'in_care','pet enters care');
select is((select count(*) from check_in_records),1::bigint,'one immutable check-in record retained');
select is((select count(*) from care_plan_snapshots),1::bigint,'one care snapshot retained');
select is((select count(*) from visit_custody_items),1::bigint,'custody item is not duplicated');
select is((select count(*) from operational_timeline_events),2::bigint,'arrival and check-in timeline events retained');
select is((select jsonb_array_length(verified_identifiers) from check_in_records),2,'two pet identifiers preserved');
select is((select jsonb_typeof(snapshot->'medications') from care_plan_snapshots),'array','care snapshot has structured medication data');
select throws_ok($$update care_plan_snapshots set snapshot='{}'$$,'P0001','commercial snapshots are immutable','care snapshot cannot be rewritten');
select throws_ok($$select app.complete_pet_check_in((select business_id from bookings),(select id from bookings),(select id from pets),'Pat Owner','owner','photo_id','["name:Milo","name:Milo"]','{}','[]','different-key')$$,'22023','two pet identifiers are required','duplicate identity signals are rejected');
select lives_ok($$select app.accept_operational_handoff((select business_id from pet_visits),(select id from pet_visits),(select id from capacity_resources),'Blue leash is in Cubby A.','handoff-once')$$,'receiving staff accepts handoff');
select is(app.accept_operational_handoff((select business_id from pet_visits),(select id from pet_visits),(select id from capacity_resources),'Blue leash is in Cubby A.','handoff-once'),(select id from operational_handoffs),'handoff retry is idempotent');
select is((select handoff_status from pet_visits),'accepted','pet handoff state is explicit');
select is((select count(*) from visit_resource_assignments),1::bigint,'one named-resource assignment created');
select is((select status from capacity_resources),'occupied','full resource becomes occupied');
select is((select count(*) from transactional_message_outbox where message_type='pet_checked_in'),1::bigint,'customer check-in communication queued once');
select is((select count(*) from operational_timeline_events),3::bigint,'handoff appends operational timeline evidence');
select throws_ok($$select app.accept_operational_handoff((select business_id from pet_visits),(select id from pet_visits),null,'Duplicate handoff','handoff-different')$$,'P0002','pet handoff unavailable','second handoff is rejected');
select throws_ok($$update operational_handoffs set handoff_notes='rewritten'$$,'P0001','commercial snapshots are immutable','accepted handoff cannot be rewritten');
select is((select ends_at-starts_at from visit_resource_assignments),(select scheduled_end-scheduled_start from operational_visits),'resource assignment covers the visit schedule');
select lives_ok($$select app.add_visit_care_amendment((select business_id from pet_visits),(select id from pet_visits),'feeding','{"instructions":"Offer half portion at first meal"}','Customer reported mild travel appetite',true,'amendment-once')$$,'visit-only care amendment added');
select is(app.add_visit_care_amendment((select business_id from pet_visits),(select id from pet_visits),'feeding','{"instructions":"Offer half portion at first meal"}','Customer reported mild travel appetite',true,'amendment-once'),(select id from care_plan_amendments),'care amendment retry is idempotent');
select is((select count(*) from care_plan_amendments),1::bigint,'one care amendment retained');
select is((select master_update_status from care_plan_amendments),'proposed','master-profile work remains a separate proposal');
select lives_ok($$select app.schedule_snapshot_care_task((select business_id from pet_visits),(select id from pet_visits),'feeding','Breakfast','{"instructions":"Offer normal breakfast portion"}',(select scheduled_start+interval '1 hour' from operational_visits),(select scheduled_start+interval '2 hours' from operational_visits),'routine',null,'feeding-task')$$,'feeding task scheduled from active snapshot');
select is(app.schedule_snapshot_care_task((select business_id from pet_visits),(select id from pet_visits),'feeding','Breakfast','{"instructions":"Offer normal breakfast portion"}',(select scheduled_start+interval '1 hour' from operational_visits),(select scheduled_start+interval '2 hours' from operational_visits),'routine',null,'feeding-task'),(select id from care_tasks where task_type='feeding'),'task scheduling retry is idempotent');
select lives_ok($$select app.start_care_task((select business_id from care_tasks),(select id from care_tasks where task_type='feeding'),'start-feeding')$$,'feeding task started');
select lives_ok($$select app.record_care_task_outcome((select business_id from care_tasks),(select id from care_tasks where task_type='feeding'),'refused','{"observation":"Would not approach bowl"}',true,'Pet refused meal after two calm offers','feeding-outcome')$$,'feeding refusal recorded');
select is(app.record_care_task_outcome((select business_id from care_tasks),(select id from care_tasks where task_type='feeding'),'refused','{"observation":"Would not approach bowl"}',true,'Pet refused meal after two calm offers','feeding-outcome'),(select id from care_task_events where idempotency_key='feeding-outcome'),'outcome retry is idempotent');
select is((select status from care_tasks where task_type='feeding'),'refused','feeding task keeps structured refusal state');
select is((select count(*) from operational_alerts),1::bigint,'feeding refusal creates one open alert');
select is((select severity from operational_alerts),'urgent','feeding refusal escalates urgently');
select is((select count(*) from care_task_events where care_task_id=(select id from care_tasks where task_type='feeding')),4::bigint,'task retains schedule start outcome and escalation events');
select is((select count(*) from operational_timeline_events),5::bigint,'care outcome appends visit timeline evidence');
select lives_ok($$select app.schedule_snapshot_care_task((select business_id from pet_visits),(select id from pet_visits),'medication','Morning medication','{"instructions":"Give labeled oral medication"}',(select scheduled_start+interval '3 hours' from operational_visits),(select scheduled_start+interval '4 hours' from operational_visits),'critical',null,'medication-task')$$,'medication task scheduled with explicit window');
select throws_ok($$select app.record_care_task_outcome((select business_id from care_tasks),(select id from care_tasks where task_type='medication'),'completed','{"observation":"Administered","five_rights_confirmed":false}',true,'','medication-unsafe')$$,'22023','medication verification required','medication cannot complete without five-rights verification');
select lives_ok($$select app.record_care_task_outcome((select business_id from care_tasks),(select id from care_tasks where task_type='medication'),'completed','{"observation":"Administered as labeled","five_rights_confirmed":true}',true,'','medication-outcome')$$,'verified medication administration recorded');
select is((select count(*) from operational_alerts),1::bigint,'successful medication does not create false alert');
select lives_ok($$select app.record_visit_observation((select business_id from pet_visits),(select id from pet_visits),'activity','yard_play','{"observation":"Calm parallel play for fifteen minutes"}','information',true,now(),'observation-info')$$,'routine activity observation recorded');
select is(app.record_visit_observation((select business_id from pet_visits),(select id from pet_visits),'activity','yard_play','{"observation":"Calm parallel play for fifteen minutes"}','information',true,now(),'observation-info'),(select id from visit_observations where idempotency_key='observation-info'),'observation retry is idempotent');
select is((select count(*) from operational_alerts),1::bigint,'routine observation creates no alert');
select lives_ok($$select app.record_visit_observation((select business_id from pet_visits),(select id from pet_visits),'wellness','mobility','{"observation":"Sudden reluctance to bear weight"}','urgent',false,now(),'observation-urgent')$$,'urgent wellness observation recorded');
select is((select count(*) from operational_alerts),2::bigint,'urgent observation creates one alert');
select is((select severity from operational_alerts where observation_id is not null),'urgent','observation alert preserves severity');
select lives_ok($$select app.transition_operational_alert((select business_id from operational_alerts),(select id from operational_alerts where observation_id is not null),'acknowledged','')$$,'care staff acknowledges alert');
select is((select status from operational_alerts where observation_id is not null),'acknowledged','alert remains active after acknowledgement');
select lives_ok($$select app.transition_operational_alert((select business_id from operational_alerts),(select id from operational_alerts where observation_id is not null),'resolved','Owner documented follow-up and safe care plan.')$$,'owner resolves alert with evidence');
select is((select status from operational_alerts where observation_id is not null),'resolved','resolved alert closes explicitly');
select lives_ok($$select app.correct_care_task_outcome((select business_id from care_tasks),(select id from care_tasks where task_type='feeding'),'completed','{"observation":"Meal was later confirmed eaten"}','Manager reconciled the signed paper record.','feeding-correction')$$,'manager appends feeding correction');
select is(app.correct_care_task_outcome((select business_id from care_tasks),(select id from care_tasks where task_type='feeding'),'completed','{"observation":"Meal was later confirmed eaten"}','Manager reconciled the signed paper record.','feeding-correction'),(select id from care_task_corrections),'correction retry is idempotent');
select is((select count(*) from care_task_events where care_task_id=(select id from care_tasks where task_type='feeding') and event_type='outcome_recorded'),1::bigint,'original outcome event remains intact');
select is((select count(*) from care_task_events where care_task_id=(select id from care_tasks where task_type='feeding') and event_type='corrected'),1::bigint,'correction appends a distinct event');
select lives_ok($$select app.initialize_service_execution((select business_id from pet_visits),(select id from pet_visits),'execution-start')$$,'boarding execution initialized after handoff');
select is(app.initialize_service_execution((select business_id from pet_visits),(select id from pet_visits),'execution-retry'),(select id from service_executions),'execution initialization retry returns existing workflow');
select is((select stage from service_executions),'settling','boarding begins in settling');
select throws_ok($$select app.transition_service_execution((select business_id from service_executions),(select id from service_executions),'ready','Premature ready attempt','execution-invalid')$$,'22023','invalid documented service transition','boarding cannot skip required stages');
select lives_ok($$select app.transition_service_execution((select business_id from service_executions),(select id from service_executions),'active','','execution-active')$$,'boarding progresses to active care');
select lives_ok($$select app.transition_service_execution((select business_id from service_executions),(select id from service_executions),'departure_preparation','','execution-departure')$$,'boarding enters departure preparation');
select lives_ok($$select app.transition_service_execution((select business_id from service_executions),(select id from service_executions),'ready','Final care and belongings review complete.','execution-ready')$$,'documented boarding service becomes ready');
select is((select stage from service_executions),'ready','service readiness remains distinct from checkout');
select lives_ok($$select app.create_playgroup_session((select id from businesses where public_slug='checkin-test'),(select id from locations),'Morning Group','mixed',8,4,2,'playgroup-session')$$,'staffed playgroup session opens');
select is(app.create_playgroup_session((select id from businesses where public_slug='checkin-test'),(select id from locations),'Morning Group','mixed',8,4,2,'playgroup-session'),(select id from playgroup_sessions),'playgroup creation retry is idempotent');
select is((select least(max_pets,pets_per_staff*staff_count) from playgroup_sessions),8,'effective group capacity respects physical and staff limits');
select throws_ok($$select app.record_daycare_evaluation((select business_id from service_executions),(select id from service_executions),'approved','{}','Calm handling response.','wrong-service-evaluation')$$,'22023','structured daycare evaluation required','boarding execution cannot receive daycare evaluation');
select * from finish();rollback;
